effect.shader:
vec2 random2( vec2 p ) {
    return fract(sin(vec2(dot(p,vec2(127.1,311.7)),dot(p,vec2(269.5,183.3))))*43758.5453);
}

// 2D multiplanar sharp noise, loosely based on Morgan McGuire @morgan3d
// https://www.shadertoy.com/view/4dS3Wd
vec2 noise (in vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Four corners in 2D of a tile
    vec2 a = random2(i);
    vec2 b = random2(i + vec2(1.0, 0.0));
    vec2 c = random2(i + vec2(0.0, 1.0));
    vec2 d = random2(i + vec2(1.0, 1.0));

    // Smooth Interpolation
    // Cubic Hermine Curve.  Same as SmoothStep()
    //vec2 u = f*f*(3.0-2.0*f);
    // u = smoothstep(0.,1.,f);

    // Sharp interpolation
    vec2 u = f;

    // Mix 4 coorners percentages
    return mix(a, b, u.x) +
            (c - a)* u.y * (1.0 - u.x) +
            (d - b) * u.x * u.y;
}

vec3 mod289(vec3 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec2 mod289(vec2 x) { return x - floor(x * (1.0 / 289.0)) * 289.0; }
vec4 mod289(vec4 x) {
  return x - floor(x * (1.0 / 289.0)) * 289.0;
}
vec3 permute(vec3 x) { return mod289(((x*34.0)+1.0)*x); }
vec4 permute(vec4 x) {
     return mod289(((x*34.0)+1.0)*x);
}

vec4 taylorInvSqrt(vec4 r)
{
  return 1.79284291400159 - 0.85373472095314 * r;
}

float snoise(vec3 v)
  {
  const vec2  C = vec2(1.0/6.0, 1.0/3.0) ;
  const vec4  D = vec4(0.0, 0.5, 1.0, 2.0);

// First corner
  vec3 i  = floor(v + dot(v, C.yyy) );
  vec3 x0 =   v - i + dot(i, C.xxx) ;

// Other corners
  vec3 g = step(x0.yzx, x0.xyz);
  vec3 l = 1.0 - g;
  vec3 i1 = min( g.xyz, l.zxy );
  vec3 i2 = max( g.xyz, l.zxy );

  //   x0 = x0 - 0.0 + 0.0 * C.xxx;
  //   x1 = x0 - i1  + 1.0 * C.xxx;
  //   x2 = x0 - i2  + 2.0 * C.xxx;
  //   x3 = x0 - 1.0 + 3.0 * C.xxx;
  vec3 x1 = x0 - i1 + C.xxx;
  vec3 x2 = x0 - i2 + C.yyy; // 2.0*C.x = 1/3 = C.y
  vec3 x3 = x0 - D.yyy;      // -1.0+3.0*C.x = -0.5 = -D.y

// Permutations
  i = mod289(i);
  vec4 p = permute( permute( permute(
             i.z + vec4(0.0, i1.z, i2.z, 1.0 ))
           + i.y + vec4(0.0, i1.y, i2.y, 1.0 ))
           + i.x + vec4(0.0, i1.x, i2.x, 1.0 ));

// Gradients: 7x7 points over a square, mapped onto an octahedron.
// The ring size 17*17 = 289 is close to a multiple of 49 (49*6 = 294)
  float n_ = 0.142857142857; // 1.0/7.0
  vec3  ns = n_ * D.wyz - D.xzx;

  vec4 j = p - 49.0 * floor(p * ns.z * ns.z);  //  mod(p,7*7)

  vec4 x_ = floor(j * ns.z);
  vec4 y_ = floor(j - 7.0 * x_ );    // mod(j,N)

  vec4 x = x_ *ns.x + ns.yyyy;
  vec4 y = y_ *ns.x + ns.yyyy;
  vec4 h = 1.0 - abs(x) - abs(y);

  vec4 b0 = vec4( x.xy, y.xy );
  vec4 b1 = vec4( x.zw, y.zw );

  //vec4 s0 = vec4(lessThan(b0,0.0))*2.0 - 1.0;
  //vec4 s1 = vec4(lessThan(b1,0.0))*2.0 - 1.0;
  vec4 s0 = floor(b0)*2.0 + 1.0;
  vec4 s1 = floor(b1)*2.0 + 1.0;
  vec4 sh = -step(h, vec4(0.0));

  vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy ;
  vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww ;

  vec3 p0 = vec3(a0.xy,h.x);
  vec3 p1 = vec3(a0.zw,h.y);
  vec3 p2 = vec3(a1.xy,h.z);
  vec3 p3 = vec3(a1.zw,h.w);

//Normalise gradients
  vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2, p2), dot(p3,p3)));
  p0 *= norm.x;
  p1 *= norm.y;
  p2 *= norm.z;
  p3 *= norm.w;

// Mix final noise value
  vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
  m = m * m;
  return 42.0 * dot( m*m, vec4( dot(p0,x0), dot(p1,x1),
                                dot(p2,x2), dot(p3,x3) ) );
}

float turbulence (in vec2 st, in int OCTAVES, in vec2 parallax, in float evolution) {
    // Initial values
    float value = 0.0;
    float amplitude = .5;
    float frequency = 0.;
    //
    // Loop of octaves
    for (int i = 0; i < OCTAVES; i++) {
        value += amplitude * abs(snoise(vec3(st,evolution)));
        st *= 2.;
        st += parallax;
        amplitude *= .5;
    }
    return value;
}


mat2 rot2d(float a) {
    float s = sin(a);
    float c = cos(a);
    return mat2(c,s,-s,c);
}

void main() {

    vec2 st = acLayerNorm;
    st -= 0.5;
    st.x *= acLayerSize.x/acLayerSize.y;

    vec2 evoseed = vec2(3.)*evolution + vec2(62.5587,137.1935)*seed;
    vec2 pixelSize = vec2(1.) / acScreenSize;
    vec2 l1 = noise(evoseed + st * rot2d(0.1) * 2. * complexity);
    vec2 l2 = noise(evoseed + st * rot2d(0.3) * 4. * complexity);
    vec2 l3 = noise(evoseed + st * rot2d(1.42) * 8. * complexity);
    vec2 l4 = noise(evoseed + st * rot2d(2.534) * 16. * complexity);
    vec2 offs = abs(abs(l1 - l2) - abs(l3 - l4));
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec4 blurTexColorMid = texture2DCv(blurBuf.texture,acScreenNorm);
    vec4 blurTexColorUp = texture2DCv(blurBuf.texture,acScreenNorm + pixelSize*vec2(0.,-4.));
    vec4 blurTexColorLeft = texture2DCv(blurBuf.texture,acScreenNorm + pixelSize*vec2(-4.,0.));
    vec4 compColor = texture2DCv(comp.texture,acScreenNorm.st);

    float dx = blurTexColorMid.a - blurTexColorLeft.a;
    float dy = blurTexColorMid.a - blurTexColorUp.a;
    vec2 norm = normalize(vec2(dx,dy));

    vec4 blurTexColor = texture2DCv(blurBuf.texture,acScreenNorm + norm*length(offs)*(disort*0.055));

    float turbBase = turbulence((st-0.5)/maskScale+0.5, 3, vec2(0.), maskEvolution + 91.935*maskSeed);
    float TINT_RANGE = 0.02;
    float turb = smoothstep( maskStrength - (TINT_RANGE+.2), maskStrength-(TINT_RANGE+.1), turbBase);
    float suppress = smoothstep( maskStrength - (TINT_RANGE+.1), maskStrength-TINT_RANGE, turbBase);
    float ttint = smoothstep( maskStrength - TINT_RANGE, maskStrength-0.001, turbBase);

    float p = blurTexColor.a;
    //float dist = distance + distOffs; //*rr;
    //float pp = smoothstep(dist+th, dist, p) * smoothstep(dist-th, dist, p);
    float dist = 1. - (distance * 0.4 + 0.5);
    float pp = pow((1.-abs(p-dist)),(1.-(thickness*0.9*suppress))*30.);
    pp *= smoothstep(0.01,0.12,p);
    pp *= smoothstep(1.0,0.999,p);

    float qq = pow((1.-abs(p-dist)),(1.-(thickness*0.9*suppress))*25.);
    qq *= smoothstep(0.01,0.12,p);
    qq *= smoothstep(1.0,0.999,p);

    if(renderContours) {
        float arad = contourAngle * 0.0174533;
        vec2 st2 = st;
        st2.y += blurTexColorMid.a*0.1;
        st2 *= rot2d(length(offs*disort*1.1)*0.2+arad);
        st2.y += blurTexColorMid.a*0.1;
        float lines = saturate(sin((st2.y+contourOffset+(offs.y*disort*0.015)) * contourCount)) * smoothstep(0.1,0.2,blurTexColorMid.a);
        //float lines = saturate(sin((st2.y+contourOffset) * contourCount)) * smoothstep(0.1,0.2,blurTexColorMid.a);
        pp += pow(lines,(1.-(thickness*0.9*suppress))*30.);
        qq += pow(lines,(1.-(thickness*0.9*suppress))*25.);
    }

    vec4 c0 = vec4(pow( vec3(pp), 1./color1.rgb),pp) * alpha;
    vec4 c1 = vec4(pow( vec3(qq), 1./color2.rgb),qq) * glowAlpha;
    vec4 c = saturate(c0 + c1);

    c *= (mix(maskColor,vec4(1.),ttint)*turb);

    gl_FragColor = texColor * fill * (1.-c.a) + c;

}
